mapper.select:
SELECT id, order_id, payment_no, channel, amount, status, trade_no, callback_time, create_time, update_time
FROM payment
WHERE id = #{id}

SELECT id, order_id, payment_no, channel, amount, status, trade_no, callback_time, create_time, update_time
FROM payment
WHERE payment_no = #{paymentNo}

mapper.update:
UPDATE payment
SET status = #{status}
WHERE id = #{id}

UPDATE payment
SET status = #{status}, update_time = NOW()
WHERE order_id = #{orderId}
